func TestDeque_ConcurrentOwnerAndStealersNoLostOrDuplicatedItems(t *testing.T) {
	const (
		totalItems = 5000
		stealers   = 8
	)

	d := NewDeque()
	start := make(chan struct{})
	pushedDone := make(chan struct{})
	results := make(chan int, totalItems)

	var wg sync.WaitGroup
	wg.Add(1)
	go func() {
		defer wg.Done()
		<-start
		for i := 0; i < totalItems; i++ {
			d.PushBottom(i)
			if i%3 == 0 {
				if item, ok := d.PopBottom(); ok {
					results <- item.(int)
				}
			}
			if i%17 == 0 {
				runtime.Gosched()
			}
		}
		close(pushedDone)

		for {
			if item, ok := d.PopBottom(); ok {
				results <- item.(int)
				continue
			}
			if d.IsEmpty() {
				return
			}
			runtime.Gosched()
		}
	}()

	for i := 0; i < stealers; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			<-start
			for {
				if item, ok := d.StealTop(); ok {
					results <- item.(int)
					continue
				}
				select {
				case <-pushedDone:
					if d.IsEmpty() {
						return
					}
				default:
				}
				runtime.Gosched()
			}
		}()
	}

	close(start)
	wg.Wait()
	close(results)

	seen := make([]bool, totalItems)
	count := 0
	for item := range results {
		if item < 0 || item >= totalItems {
			t.Fatalf("unexpected item %d", item)
		}
		if seen[item] {
			t.Fatalf("duplicate item %d", item)
		}
		seen[item] = true
		count++
	}
	if count != totalItems {
		t.Fatalf("expected %d items, got %d", totalItems, count)
	}
	for item, ok := range seen {
		if !ok {
			t.Fatalf("missing item %d", item)
		}
	}
	if !d.IsEmpty() {
		t.Fatalf("deque should be empty, got len %d", d.Len())
	}
}

