   194		ns.clock++
   195	
   196		synced := 0
   197		peerList := ns.peerList()
   198		if len(peerList) < 2 {
   199			return 0
   200		}
   201	
   202		for nodeID, store := range ns.stores {
   203			// Pick a random peer
   204			sel := gossip.NewRandomPeerSelector(ns.rng.Int63())
   205			peers := sel.SelectPeers(peerList, nodeID, 1)
   206			if len(peers) == 0 {
   207				continue
   208			}
   209			peerID := peers[0]
   210			if ns.isPartitioned(nodeID, peerID) {
   211				continue
   212			}
   213	
   214			peerStore, ok := ns.stores[peerID]
   215			if !ok {
   216				continue
   217			}
   218	
   219			// Build merkle trees from both stores
   220			localTree := storeToTree(store)
   221			remoteTree := storeToTree(peerStore)
   222			diff := merkle.FastDiff(localTree, remoteTree)
   223	
   224			// Sync differing keys using Apply to preserve versions
   225			for _, key := range diff.OnlyRemote {
   226				e, ok := peerStore.GetEntry(key)
   227				if ok {
   228					store.Apply([]*gossip.StateEntry{e})
   229					synced++
   230				}
   231			}
   232			for _, key := range diff.OnlyLocal {
   233				e, ok := store.GetEntry(key)
   234				if ok {
   235					peerStore.Apply([]*gossip.StateEntry{e})
   236					synced++
   237				}
   238			}
   239			for _, key := range diff.Different {
   240				le, _ := store.GetEntry(key)
   241				re, _ := peerStore.GetEntry(key)
   242				if le != nil && re != nil {
   243					if le.Version > re.Version {
   244						peerStore.Apply([]*gossip.StateEntry{le})
   245					} else {
   246						store.Apply([]*gossip.StateEntry{re})
   247					}
   248					synced++
   249				}
   250			}
   251	
   252			ns.recordEvent(Event{
   253				Time:    ns.clock,
   254				Type:    EventMerkleDiff,
   255				Source:  nodeID,
   256				Target:  peerID,
   257				Payload: diff.TotalDiffs(),
   258			})
   259		}
   260		return synced
   261	}
