   263	func (ns *NetworkSim) recordEvent(event Event) {
   264		if len(ns.events) == maxEventLog {
   265			copy(ns.events, ns.events[1:])
   266			ns.events[maxEventLog-1] = event
   267			return
   268		}
   269		ns.events = append(ns.events, event)
   270	}
   271	
   272	func storeToTree(store *gossip.StateStore) *merkle.Tree {
   273		tree := merkle.NewTree()
   274		entries := make(map[string][]byte)
   275		for _, key := range store.Keys() {
   276			v, ok := store.Get(key)
   277			if ok {
   278				entries[key] = v
   279			}
   280		}
   281		tree.PutBatch(entries)
   282		return tree
   283	}
   284	
   285	func (ns *NetworkSim) peerList() []string {
   286		list := make([]string, 0, len(ns.nodes))
   287		for id := range ns.nodes {
   288			list = append(list, id)
   289		}
   290		sort.Strings(list)
   291		return list
   292	}
