   294	// Converged checks if all nodes have the same state hash.
   295	func (ns *NetworkSim) Converged() bool {
   296		ns.mu.Lock()
   297		defer ns.mu.Unlock()
   298		var firstHash [32]byte
   299		first := true
   300		for _, store := range ns.stores {
   301			h := store.Hash()
   302			if first {
   303				firstHash = h
   304				first = false
   305			} else if h != firstHash {
   306				return false
   307			}
   308		}
   309		return true
   310	}

